mapper.select:
SELECT COUNT(*)
FROM problem p
LEFT JOIN user_problem up ON p.id = up.problem_id AND up.user_id = #{userId}


        AND p.difficulty = #{difficulty}


        AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%'))


        AND up.status = #{status}


        AND EXISTS (
            SELECT 1 FROM problem_category pc2
            JOIN category c2 ON pc2.category_id = c2.id
            WHERE pc2.problem_id = p.id
            AND c2.name IN

                #{name}

        )

SELECT p.id, p.title, p.difficulty, p.pass_rate
FROM problem p
LEFT JOIN user_problem up ON p.id = up.problem_id AND up.user_id = #{userId}


        AND p.difficulty = #{difficulty}


        AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%'))


        AND up.status = #{status}


        AND EXISTS (
            SELECT 1 FROM problem_category pc2
            JOIN category c2 ON pc2.category_id = c2.id
            WHERE pc2.problem_id = p.id
            AND c2.name IN

                #{name}

        )


ORDER BY p.id
LIMIT #{offset}, #{size}

SELECT status
FROM user_problem
WHERE user_id = #{userId} AND problem_id = #{problemId}

SELECT username
FROM user
WHERE id = #{userId}
